package com.travelassistant.consultation;import jakarta.persistence.LockModeType;import java.time.Instant;import java.util.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;
public interface ConversationRepository extends JpaRepository<Conversation,String>{@Lock(LockModeType.PESSIMISTIC_WRITE)@Query("select c from Conversation c where c.id=:id and c.user.id=:user")Optional<Conversation> lockOwned(@Param("id")String id,@Param("user")String user);Optional<Conversation>findByIdAndUserId(String id,String user);Page<Conversation>findByUserIdOrderByUpdatedAtDescIdDesc(String user,Pageable page);@Query("select c from Conversation c where c.user.id=:user and (c.updatedAt<:time or (c.updatedAt=:time and c.id<:id)) order by c.updatedAt desc,c.id desc")List<Conversation>findAfter(@Param("user")String user,@Param("time")Instant time,@Param("id")String id,Pageable page);@Modifying@Query(value="update conversations set updated_at=current_timestamp(6) where id=:id",nativeQuery=true)void touch(@Param("id")String id);}
